// Helper function to check if S is a rotation of B using the drop counting property.
// S must be the sorted version of B.
func isRotation(B, S []int64, k int) bool {
	if k == 0 {
		return true
	}

	// Check if S is constant (all elements are equal)
	isConstant := true
	for i := 1; i < k; i++ {
		if S[i] != S[0] {
			isConstant = false
			break
		}
	}

	// Calculate the number of circular drops in B
	dropCount := 0
	for i := 0; i < k; i++ {
		next := (i + 1) % k
		if B[i] > B[next] {
			dropCount++
		}
	}

	if isConstant {
		// If S is constant, B must also be constant, and drop count must be 0.
		return dropCount == 0
	} else {
		// If S is not constant, B must have exactly one drop point (circularly) to be a rotation of S.
		return dropCount == 1
	}
}

func solve(nums []int64) int64 {
	N := len(nums)
	if N == 0 {
		return 0
	}

	// 1. Find all divisors k
	divisors := []int64{}
	for k := int64(1); k*k <= int64(N); k++ {
		if int64(N)%k == 0 {
			divisors = append(divisors, k)
			if k*k != int64(N) {
				divisors = append(divisors, int64(N)/k)
			}
		}
	}

	// Check if nums is already sorted (required for k=1 case)
	isGloballySorted := true
	for i := 0; i < N-1; i++ {
		if nums[i] > nums[i+1] {
			isGloballySorted = false
			break
		}
	}

	totalSum := int64(0)

	for _, k := range divisors {
		kInt := int(k)

		if k == 1 {
			// k=1 only works if the array is already sorted, as operations do nothing.
			if isGloballySorted {
				totalSum += 1
			}
			continue
		}

		// k > 1: Check block conditions
		isKSortable := true
		numBlocks := N / kInt

		for i := 0; i < numBlocks; i++ {
			start := i * kInt
			end := start + kInt

			// Extract block B_i
			B := make([]int64, kInt)
			copy(B, nums[start:end])

