func solve(nums []int64) int64 {
	n := len(nums)

	// 1. Create sorted version S
	S := make([]int64, n)
	copy(S, nums)
	sort.Slice(S, func(i, j int) bool {
		return S[i] < S[j]
	})

	// Helper function to check if B is a cyclic shift of A (both length k)
	// This implementation runs in O(k^2).
	isCyclicShift := func(A, B []int64) bool {
		k := len(A)
		if k == 0 {
			return true
		}

		// Try all k rotations of A. A rotation is defined by its starting element index j in A.
		for j := 0; j < k; j++ {
			match := true
			// Check if B matches A rotated by j
			for l := 0; l < k; l++ {
				// The element at index l of the rotation starting at j is A[(j + l) % k]
				if B[l] != A[(j+l)%k] {
					match = false
					break
				}
			}
			if match {
				return true
			}
		}
		return false
	}

	// 2. Find all divisors k of n
	divisors := make(map[int]bool)
	for i := 1; i*i <= n; i++ {
		if n%i == 0 {
			divisors[i] = true
			divisors[n/i] = true
		}
	}

	var totalSum int64 = 0

	// 3. Check each divisor k
	for k := range divisors {
		if k == 0 {
			continue
		}

		isKSortable := true

		// Iterate over m = n/k segments
		for i := 0; i < n/k; i++ {
			start := i * k
			end := (i + 1) * k

			// A is the subarray from nums
			A := nums[start:end]
			// Si is the corresponding segment from the sorted array S
			Si := S[start:end]

			// Check if S_i is a cyclic shift of A
			if !isCyclicShift(A, Si) {
				isKSortable = false
				break
			}
		}

		if isKSortable {
			totalSum += int64(k)
		}
	}

	return totalSum
}
